/// <summary>
/// Warehouse import
/// </summary>
public class ETG_Acu_InventWarehouseImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_InventWarehouseImport  inventSiteImport;

    inventSiteImport = ETG_Acu_InventWarehouseImport::construct();

    if (inventSiteImport.prompt())
    {
        inventSiteImport.runOperation();
    }
}

public static ETG_Acu_InventWarehouseImport construct()
{
    return new ETG_Acu_InventWarehouseImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    InventWarehouseEntity   warehouse;

    InventLocationId    inventLocationId;
    InventSiteId        siteId;
    InventLocationType  locationType;

    DictEnum            dictEnum = new DictEnum(enumNum(InventLocationType));

    inventLocationId    = conpeek(_con, 1);
    siteId              = conpeek(_con, 3);
    locationType        = dictEnum.symbol2Value(conpeek(_con, 6));

    select firstonly forupdate warehouse
        where warehouse.WarehouseId         == inventLocationId
            && warehouse.OperationalSiteId  == siteId;

    if (!warehouse)
    {
        warehouse.WarehouseId                       = conpeek(_con, 1);
        warehouse.AreItemsCoveragePlannedManually   = conpeek(_con, 2);
        warehouse.OperationalSiteId                 = conpeek(_con, 3);
        warehouse.TransitWarehouseId                = conpeek(_con, 4);
        warehouse.WarehouseName                     = conpeek(_con, 5);
        warehouse.WarehouseType                     = locationType;
        warehouse.insert();
    }
    else
    {
        warehouse.AreItemsCoveragePlannedManually   = conpeek(_con, 2);
        warehouse.TransitWarehouseId                = conpeek(_con, 4);
        warehouse.WarehouseName                     = conpeek(_con, 5);
        warehouse.WarehouseType                     = locationType;
        warehouse.update();
    }
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpWarhouse";

    return ret;
}
